/**
 * 대운(大運) 계산.
 *
 * - 순행/역행: 연간(年干)의 음양과 성별로 결정한다.
 *   양남·음녀 → 순행, 음남·양녀 → 역행.
 * - 대운 간지: 월주(月柱)에서 시작해 순행이면 다음 간지, 역행이면 이전 간지로 전개.
 * - 대운수(시작 나이): 출생에서 다음(순행)/이전(역행) 절(節)까지의 일수를 3으로 나눈 값.
 */
import type { Gender, LuckPillarInfo, Pillar } from '../types';
export interface LuckPillarParams {
    /** 출생 절대 순간 (UTC ms) */
    instantUTCms: number;
    /** 입력 양력 연도 (절 수집 범위) */
    birthYear: number;
    /** 월주 */
    monthPillar: Pillar;
    /** 사주 연간(年干) 인덱스 (0~9) */
    sajuYearStemIndex: number;
    /** 성별 */
    gender: Gender;
    /** 생성할 대운 개수 (기본 10) */
    count?: number;
}
/**
 * 대운 정보를 계산한다.
 */
export declare function getLuckPillars(params: LuckPillarParams): LuckPillarInfo;
